def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[7]  # Slide 8 is index 7
    for shape in slide.shapes:
        if shape.shape_type == 19:  # MSO_SHAPE_TYPE.TABLE
            table = shape.table
            if table.columns.__len__() == 2:
                return "Table with two columns found on slide 8.", 1.0
            else:
                return f"Table found, but has {table.columns.__len__()} columns instead of 2.", 0.0
    return "No table found on slide 8.", 0.0

def compute_score() -> tuple[str, float]:
    if ppt_diff.added_slides or ppt_diff.removed_slides:
        extraneous = True
        reason_list.append('Slides added or removed.')
    # Animations or transitions
    if ppt_diff.added_animations or ppt_diff.removed_animations or ppt_diff.modified_animations:
        extraneous = True
        reason_list.append('Animations changed.')
    if ppt_diff.added_transitions or ppt_diff.removed_transitions or ppt_diff.modified_transitions:
        extraneous = True
        reason_list.append('Transitions changed.')
    # Only slide 8 should be modified
    other_mods = []
    for (old, new) in ppt_diff.modified_slides:
        if old.slide_number != 8:
            other_mods.append(old.slide_number)
    added_nums = [slide.slide_number for slide in ppt_diff.added_slides if slide.slide_number != 8]
    removed_nums = [slide.slide_number for slide in ppt_diff.removed_slides if slide.slide_number != 8]
    changed = set(other_mods + added_nums + removed_nums)
    if len(changed) == 0:
        return "No extraneous changes on other slides.", 1.0
    else:
        return f"Extraneous changes on slides: {sorted(changed)}.", 0.0
